; マップを開いた時に必ず実行されるスクリプト
[initial]

if(! loading) events.push2(2, 3, 4, 5);

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4, 5, 6, 7]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@notice text="This is a temple for those who can dive underwater. You will find what you seek in the water."

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] true
*event_3
;[exp] true
*event_4
;[exp] true
*event_5
;[exp] true

@callbattle normal=true

[eventoff]
;-------------------------------------------------------------------------------
*event_6
;[exp] onObjectTrigger

@question title="There is a stone monument. Would you like to touch it?"
[eventoff cond='! tf.result']
@wait time=500
@playse storage=tremble
@quake time=3000 hmax=5 vmax=0
@wq
@playse storage=rockdrop
@changewall x=12 y=9 way=s himg=arch type=space behind=true
@wait time=800
@notice text="I heard the sound of something heavy moving somewhere!"
@delevent

[eventoff]
;-------------------------------------------------------------------------------
*event_7
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("luck", 2)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had Luck permanently increased by 2!"'

[eventoff]
;-------------------------------------------------------------------------------
